import React, { useState, useEffect } from 'react';
import './Registration.css';

function Register() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    service: 'Web Development',
    paymentMethod: 'Online',
    transactionId: '',
    message: ''
  });

  const [price, setPrice] = useState(0);

  useEffect(() => {
    const prices = {
      'Web Development': 5000,
      'UI/UX Design': 3000,
      'App Development': 8000,
      'Assignment Support': 500,
      'PPT Design': 300,
      'Report Writing': 400
    };
    setPrice(prices[formData.service]);
  }, [formData.service]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    alert(`Success! Payment Mode: ${formData.paymentMethod}`);
  };

  return (
    <div className="register-container bg-light overflow-hidden">
      <div className="container py-3">
        <div className="row justify-content-center align-items-center min-vh-100">
          <div className="col-md-5 col-lg-4">
            <div className="card shadow border-0 rounded-4 overflow-hidden">
              <div className="card-body p-4">
                <h4 className="fw-bold text-center mb-1 text-primary">Registration</h4>
                <p className="text-center text-muted small mb-3">Quick service booking</p>
                
                <form onSubmit={handleSubmit}>
                  <div className="mb-2">
                    <label className="form-label fw-bold extra-small mb-1">Full Name</label>
                    <input type="text" name="name" className="form-control form-control-sm" required onChange={handleChange} />
                  </div>

                  <div className="mb-2">
                    <label className="form-label fw-bold extra-small mb-1">Email Address</label>
                    <input type="email" name="email" className="form-control form-control-sm" required onChange={handleChange} />
                  </div>

                  <div className="mb-2">
                    <label className="form-label fw-bold extra-small mb-1">Select Service</label>
                    <select name="service" className="form-select form-select-sm" onChange={handleChange} value={formData.service}>
                      <option value="Web Development">Web Development</option>
                      <option value="UI/UX Design">UI/UX Design</option>
                      <option value="App Development">App Development</option>
                      <option value="Assignment Support">Assignment Support</option>
                      <option value="PPT Design">PPT Design</option>
                      <option value="Report Writing">Report Writing</option>
                    </select>
                  </div>

                  <div className="payment-mini-box border rounded p-2 bg-white mt-3">
                    <div className="d-flex justify-content-between mb-2">
                      <span className="small fw-bold">Cost:</span>
                      <span className="text-primary fw-bold">₹{price}</span>
                    </div>

                    <div className="d-flex gap-2 mb-2">
                      <div className="form-check small flex-fill border rounded px-2 py-1 bg-light">
                        <input className="form-check-input" type="radio" name="paymentMethod" id="online" value="Online" checked={formData.paymentMethod === 'Online'} onChange={handleChange} />
                        <label className="form-check-label" htmlFor="online">Online</label>
                      </div>
                      <div className="form-check small flex-fill border rounded px-2 py-1 bg-light">
                        <input className="form-check-input" type="radio" name="paymentMethod" id="cash" value="Cash" checked={formData.paymentMethod === 'Cash'} onChange={handleChange} />
                        <label className="form-check-label" htmlFor="cash">Cash</label>
                      </div>
                    </div>

                    {formData.paymentMethod === 'Online' && (
                      <div>
                        <input type="text" name="transactionId" className="form-control form-control-sm" placeholder="Ref No." required onChange={handleChange} />
                      </div>
                    )}
                  </div>

                  <button type="submit" className="btn btn-primary w-100 fw-bold mt-3 shadow-sm py-2">
                    SUBMIT
                  </button>
                </form>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Register;
